const WINDOW_SECONDS  = 60;       // rolling window in seconds

// In-memory store: ip -> array of timestamps (Unix seconds)
const ipTimestamps = {};

// Clean up stale entries periodically to avoid unbounded memory growth
cronAdd("cleanup_rate_limit_store", "* * * * *", () => {
    const now = Math.floor(Date.now() / 1000);
    const cutoff = now - WINDOW_SECONDS;
    for (const ip in ipTimestamps) {
        // filter out timestamps outside the window
        ipTimestamps[ip] = ipTimestamps[ip].filter(t => t > cutoff);
        if (ipTimestamps[ip].length === 0) {
            delete ipTimestamps[ip];
        }
    }
});

