    const req = e.request;

    // Only intercept POST to the users signup endpoint
    if (req.method !== "POST") {
        return e.next();
    }

    const path = req.url.path;
    // Match exactly /api/collections/users/records
    if (path !== "/api/collections/users/records") {
        return e.next();
    }

    // Determine client IP
    // e.realIP() returns the real IP taking X-Forwarded-For into account
    let ip = e.realIP();
    if (!ip) {
        ip = "unknown";
    }

    const nowSec = Math.floor(Date.now() / 1000);
    const cutoff  = nowSec - WINDOW_SECONDS;

    // Initialize or prune timestamps for this IP
    if (!ipTimestamps[ip]) {
        ipTimestamps[ip] = [];
    }
    ipTimestamps[ip] = ipTimestamps[ip].filter(t => t > cutoff);

    if (ipTimestamps[ip].length >= RATE_LIMIT) {
        // Calculate when the oldest request in the window will expire
        const oldest      = ipTimestamps[ip][0];
        const retryAfter  = Math.max(1, (oldest + WINDOW_SECONDS) - nowSec + 1);

        e.response.header().set("Retry-After", String(retryAfter));
        e.response.header().set("Content-Type", "application/json");

        return e.json(429, { retryAfter: retryAfter });
    }

    // Record this request timestamp
    ipTimestamps[ip].push(nowSec);

    return e.next();
});

